def copy_repo_fixture(tmp_path: Path) -> Path:
    """Copy the small project into a temp repo for git mutation tests."""
    source = Path.cwd()
    repo = tmp_path / "repo"
    repo.mkdir()
    for directory in (
        "agents",
        "backtester",
        "config",
        "data",
        "docs",
        "orchestrator",
        "reports",
        "schemas",
        "strategies",
    ):
        shutil.copytree(
            source / directory,
            repo / directory,
            ignore=shutil.ignore_patterns("__pycache__"),
        )
    for filename in ("AGENTS.md", "README.md", "TASK.md", "pyproject.toml", ".gitignore"):
        shutil.copy2(source / filename, repo / filename)
    (repo / "experiments").mkdir()
    (repo / "experiments" / ".gitkeep").write_text("", encoding="utf-8")
    return repo


def refresh_operator_views(repo: Path, run_id: str) -> None:
    """Refresh source-hash-bound operator views after operator artifacts change."""
    run_dir = repo / "experiments" / run_id
    write_operator_action_dashboard(
        run_dir=run_dir,
        experiments_dir=repo / "experiments",
        repo_root=repo,
    )
    write_operator_unlock_checklist(
        run_dir=run_dir,
        repo_root=repo,
    )
    write_operator_cockpit(
        run_dir=run_dir,
        experiments_dir=repo / "experiments",
        repo_root=repo,
    )


def assert_matches_schema(payload_path: Path, schema_name: str) -> None:
    """Assert a JSON artifact matches one repository contract schema."""
    schema_path = Path.cwd() / "schemas" / f"{schema_name}.schema.json"
    assert validate_json_file(payload_path=payload_path, schema_path=schema_path) == ()


def assert_matches_schema_payload(payload: object, schema_name: str) -> None:
    """Assert a JSON payload matches one repository contract schema."""
    schema_path = Path.cwd() / "schemas" / f"{schema_name}.schema.json"
    schema = json.loads(schema_path.read_text(encoding="utf-8"))
    assert validate_json_payload(payload=payload, schema=schema) == ()


def test_schema_validator_resolves_local_defs_refs() -> None:
    schema = {
        "type": "object",
        "required": ["record"],
        "properties": {
            "record": {
                "$ref": "#/$defs/record",
            },
        },
        "$defs": {
            "record": {
                "type": "object",
                "required": ["ok"],
                "properties": {
                    "ok": {
                        "type": "boolean",
                    },
                },
                "additionalProperties": False,
            },
        },
    }

    assert validate_json_payload(payload={"record": {"ok": True}}, schema=schema) == ()
    errors = validate_json_payload(payload={"record": {"ok": "yes"}}, schema=schema)

    assert "$.record.ok: expected boolean, got string" in errors


def test_schema_validator_resolves_same_directory_schema_refs(tmp_path: Path) -> None:
    defs_schema = {
        "$defs": {
            "record": {
                "type": "object",
                "required": ["ok"],
                "properties": {
                    "ok": {
                        "type": "boolean",
                    },
                },
                "additionalProperties": False,
            },
        },
    }
    wrapper_schema = {
        "type": "object",
        "required": ["record"],
        "properties": {
            "record": {
                "$ref": "defs.schema.json#/$defs/record",
            },
        },
    }
    defs_path = tmp_path / "defs.schema.json"
    wrapper_path = tmp_path / "wrapper.schema.json"
    payload_path = tmp_path / "payload.json"
    defs_path.write_text(json.dumps(defs_schema), encoding="utf-8")
    wrapper_path.write_text(json.dumps(wrapper_schema), encoding="utf-8")
    payload_path.write_text(json.dumps({"record": {"ok": True}}), encoding="utf-8")

    assert validate_json_file(payload_path=payload_path, schema_path=wrapper_path) == ()
    errors = validate_json_payload(
        payload={"record": {"ok": "yes"}},
        schema=wrapper_schema,
        schema_dir=tmp_path,
    )

    assert "$.record.ok: expected boolean, got string" in errors


def test_artifact_validator_coverage_reports_repo_contracts(tmp_path: Path) -> None:
    payload = build_artifact_validator_coverage(repo_root=Path.cwd())

    assert payload["schema_version"] == ARTIFACT_VALIDATOR_COVERAGE_SCHEMA_VERSION
    assert_matches_schema_payload(payload, "artifact_validator_coverage")
    schema_count = len(list(Path("schemas").glob("*.schema.json")))
    assert payload["totals"]["schema_count"] == schema_count
    rows = {
        str(row["schema_name"]): row
        for row in payload["schemas"]
        if isinstance(row, dict)
    }
    assert rows["agent_input"]["validator_covered"] is True
    assert rows["agent_input"]["docs_covered"] is True
    assert rows["strategy_proposal"]["validator_covered"] is True
    assert rows["strategy_proposal"]["docs_covered"] is True
    assert rows["strategy_proposal"]["tests_covered"] is True
    assert rows["strategy_proposal"]["inspection_or_replay_supported"] is True
    assert rows["artifact_validator_coverage"]["tests_covered"] is True
    assert rows["artifact_validator_coverage"]["docs_covered"] is True
    assert rows["champion"]["validator_covered"] is True
    assert payload["ok"] is True
    assert payload["gaps"] == []

    output_path = tmp_path / "artifact_validator_coverage.json"
    markdown_path = tmp_path / "artifact_validator_coverage.md"
    written = write_coverage_report(
        output_path=output_path,
        markdown_path=markdown_path,
        repo_root=Path.cwd(),
    )
    assert written["schema_version"] == ARTIFACT_VALIDATOR_COVERAGE_SCHEMA_VERSION
    assert validate_coverage_payload_file(
        payload_path=output_path,
        repo_root=Path.cwd(),
    ) == ()
    assert "# Artifact Validator Coverage" in coverage_markdown(payload)
    assert "Schemas with gaps" in markdown_path.read_text(encoding="utf-8")


def test_artifact_validator_coverage_reports_new_schema_gap(tmp_path: Path) -> None:
    repo = copy_repo_fixture(tmp_path)
    schema_path = repo / "schemas/uncovered_demo.schema.json"
    schema_path.write_text(
        json.dumps(
            {
                "$schema": "https://json-schema.org/draft/2020-12/schema",
                "title": "Uncovered Demo",
                "type": "object",
                "required": ["schema_version"],
                "properties": {
                    "schema_version": {
                        "type": "string",
                        "enum": ["uncovered_demo_v1"],
                    }
                },
            },
            indent=2,
            sort_keys=True,
        )
        + "\n",
        encoding="utf-8",
    )

    payload = build_artifact_validator_coverage(repo_root=repo)
    rows = {
        str(row["schema_name"]): row
        for row in payload["schemas"]
        if isinstance(row, dict)
    }

    gap_codes = rows["uncovered_demo"]["gap_codes"]
    assert "validator_missing" in gap_codes
    assert "docs_missing" in gap_codes
