def test_experiment_scope_health_cli_and_experiments_command(
    tmp_path: Path,
) -> None:
    repo = copy_repo_fixture(tmp_path)
    history_path = repo / "experiments/run_artifact_health_history.jsonl"
    run_iteration_loop(
        run_id="scope-health-cli",
        max_rounds=1,
        repo_root=repo,
    )
    health = build_run_artifact_health(
        experiments_dir=repo / "experiments",
        repo_root=repo,
        run_ids=["scope-health-cli"],
    )
    append_run_artifact_health_history(
        payload=health,
        history_path=history_path,
        recorded_at="2026-01-01T00:00:00Z",
    )
    strategy_before = (repo / "strategies/current_strategy.py").read_text(
        encoding="utf-8"
    )

    direct_result = subprocess.run(
        [
            sys.executable,
            "-m",
            "orchestrator.experiment_scope_health",
            "--experiments-dir",
            str(repo / "experiments"),
            "--repo-root",
            str(repo),
            "--history-path",
            str(history_path),
            "--created-at-from",
            "2026-01-01T00:00:00Z",
            "--output",
            str(repo / "experiment_scope_health.json"),
            "--strict",
        ],
        cwd=repo,
        check=True,
        capture_output=True,
        text=True,
    )
    experiments_result = subprocess.run(
        [
            sys.executable,
            "-m",
            "orchestrator.experiments",
            "--experiments-dir",
            str(repo / "experiments"),
            "scope-health",
            "--history-path",
            str(history_path),
            "--created-at-from",
            "2026-01-01T00:00:00Z",
            "--strict",
        ],
        cwd=repo,
        check=True,
        capture_output=True,
        text=True,
    )
    direct_payload = json.loads(direct_result.stdout)
    experiments_payload = json.loads(experiments_result.stdout)

    assert direct_payload["schema_version"] == EXPERIMENT_SCOPE_HEALTH_SCHEMA_VERSION
    assert experiments_payload["schema_version"] == EXPERIMENT_SCOPE_HEALTH_SCHEMA_VERSION
    assert direct_payload["scope"]["created_at_from"] == "2026-01-01T00:00:00Z"
    assert experiments_payload["scope"]["created_at_from"] == "2026-01-01T00:00:00Z"
    assert direct_payload["ok"] is True
    assert experiments_payload["ok"] is True
    assert direct_payload["policy"]["does_not_run_backtests"] is True
    assert experiments_payload["policy"]["does_not_change_acceptance"] is True
    assert_matches_schema(repo / "experiment_scope_health.json", "experiment_scope_health")
    assert (
        repo / "strategies/current_strategy.py"
    ).read_text(encoding="utf-8") == strategy_before


def test_memory_hygiene_scopes_filter_history(tmp_path: Path) -> None:
    repo = copy_repo_fixture(tmp_path)
    memory_path = repo / "experiments/memory.jsonl"
    patch_hash = "abc123" * 11
    records = [
        {
            "created_at": "2026-01-01T00:00:00Z",
            "kind": "proposal_outcome",
            "run_id": "old-a",
            "round_id": "round_001",
            "agent_name": "stub",
            "direction_tag": "lower_min_edge",
            "patch_sha256": patch_hash,
            "accepted": False,
            "applicable": True,
            "validation_ev_delta": 0.0,
        },
        {
            "created_at": "2026-01-02T00:00:00Z",
            "kind": "proposal_outcome",
            "run_id": "old-b",
            "round_id": "round_001",
            "agent_name": "stub",
            "direction_tag": "lower_min_edge",
            "patch_sha256": patch_hash,
            "accepted": False,
            "applicable": True,
            "validation_ev_delta": 0.0,
        },
        {
            "created_at": "2026-02-01T00:00:00Z",
            "kind": "proposal_outcome",
            "run_id": "new-a",
            "round_id": "round_001",
            "agent_name": "stub",
            "direction_tag": "lower_min_edge",
            "patch_sha256": patch_hash,
            "accepted": False,
            "applicable": True,
            "validation_ev_delta": 0.0,
        },
    ]
    memory_path.write_text(
        "\n".join(json.dumps(record, sort_keys=True) for record in records) + "\n",
        encoding="utf-8",
    )

    full_reason = memory_filter_rejection_reason(
        experiments_dir=repo / "experiments",
        patch_sha256=patch_hash,
        threshold=2,
    )
    scoped_reason = memory_filter_rejection_reason(
        experiments_dir=repo / "experiments",
        patch_sha256=patch_hash,
        threshold=2,
        created_at_from="2026-02-01T00:00:00Z",
    )
    recent_reason = memory_filter_rejection_reason(
        experiments_dir=repo / "experiments",
        patch_sha256=patch_hash,
        threshold=2,
        recent_record_limit=1,
    )
    hygiene = build_memory_hygiene(
        experiments_dir=repo / "experiments",
        repo_root=repo,
        failed_patch_threshold=2,
        failed_direction_threshold=2,
        created_at_from="2026-02-01T00:00:00Z",
    )
    output_path = repo / "memory_hygiene.json"
    markdown_path = repo / "memory_hygiene.md"
    written = write_memory_hygiene(
        output_path=output_path,
        markdown_path=markdown_path,
        experiments_dir=repo / "experiments",
        repo_root=repo,
        failed_patch_threshold=2,
        failed_direction_threshold=2,
        created_at_from="2026-02-01T00:00:00Z",
    )

    assert "memory filter rejected patch" in full_reason
    assert scoped_reason == ""
    assert recent_reason == ""
    assert hygiene["schema_version"] == MEMORY_HYGIENE_SCHEMA_VERSION
    assert hygiene["totals"]["total_record_count"] == 3
    assert hygiene["totals"]["active_record_count"] == 1
    assert hygiene["totals"]["ignored_by_created_at_count"] == 2
    assert hygiene["totals"]["patch_block_count"] == 0
    assert hygiene["policy"]["does_not_delete_memory"] is True
    assert written["schema_version"] == MEMORY_HYGIENE_SCHEMA_VERSION
    assert "# Memory Hygiene" in markdown_path.read_text(encoding="utf-8")
    assert_matches_schema_payload(hygiene, "memory_hygiene")
    assert validate_memory_hygiene_payload(
        hygiene,
        experiments_dir=repo / "experiments",
        repo_root=repo,
        failed_patch_threshold=2,
        failed_direction_threshold=2,
        created_at_from="2026-02-01T00:00:00Z",
        require_current_evidence=True,
    ) == ()
    drift_hygiene = json.loads(json.dumps(hygiene))
    drift_hygiene["totals"]["active_record_count"] = 999
    drift_errors = validate_memory_hygiene_payload(
        drift_hygiene,
        experiments_dir=repo / "experiments",
        repo_root=repo,
        failed_patch_threshold=2,
        failed_direction_threshold=2,
        created_at_from="2026-02-01T00:00:00Z",
        require_current_evidence=True,
    )
    assert "memory_hygiene consistency mismatch: active totals" in drift_errors
    assert "memory_hygiene current evidence mismatch" in drift_errors
    assert validate_memory_hygiene_file(payload_path=output_path, repo_root=repo) == ()


def test_memory_scope_recommendation_suggests_recent_limit(
    tmp_path: Path,
) -> None:
    repo = copy_repo_fixture(tmp_path)
    run_dir = repo / "experiments/scope-rec"
    run_dir.mkdir(parents=True)
