    approval_result = subprocess.run(
        [
            sys.executable,
            "-m",
            "orchestrator.champion_promotion_approval",
            "experiments/receipt-candidate",
            "--approve",
            "--operator-id",
            "test-operator",
            "--confirmation-phrase",
            CHAMPION_PROMOTION_CONFIRMATION_PHRASE,
        ],
        cwd=repo,
        capture_output=True,
        text=True,
        check=False,
    )
    promote_result = subprocess.run(
        [
            sys.executable,
            "-m",
            "orchestrator.experiments",
            "promote-approved",
            "receipt-candidate",
            "--approval-path",
            "experiments/receipt-candidate/champion_promotion_approval.json",
        ],
        cwd=repo,
        capture_output=True,
        text=True,
        check=False,
    )

    assert approval_result.returncode == 0, approval_result.stderr
    assert promote_result.returncode == 0, promote_result.stderr
    approval = json.loads(approval_result.stdout)
    receipt = json.loads(promote_result.stdout)
    champion = show_champion(experiments_dir=repo / "experiments")["champion"]
    receipt_path = repo / "experiments/receipt-candidate/champion_promotion_receipt.json"
    receipt_md = repo / "experiments/receipt-candidate/champion_promotion_receipt.md"

    assert approval["status"] == "approval_recorded"
    assert receipt["schema_version"] == CHAMPION_PROMOTION_RECEIPT_SCHEMA_VERSION
    assert receipt["status"] == "promoted"
    assert receipt["promoted"] is True
    assert receipt["base_run_id"] == "receipt-champion"
    assert receipt["evidence_checks"]["ok"] is True
    assert receipt["evidence_checks"]["blockers"] == []
    assert receipt["policy"]["requires_approval_artifact"] is True
    assert receipt["policy"]["writes_only_champion_registry_and_history"] is True
    assert receipt["policy"]["does_not_execute_agents"] is True
    assert champion["champion_run_id"] == "receipt-candidate"
    champion_status = show_champion(experiments_dir=repo / "experiments")
    assert champion_status["lineage_summary"]["event_count"] == 2  # type: ignore[index]
    assert champion_status["lineage_summary"]["approved_receipt_count"] == 1  # type: ignore[index]
    assert champion_status["lineage_summary"]["legacy_direct_count"] == 1  # type: ignore[index]
    assert champion_status["lineage_summary"]["latest_champion_run_id"] == "receipt-candidate"  # type: ignore[index]
    assert receipt_path.exists()
    assert receipt_md.exists()
    assert_matches_schema(receipt_path, "champion_promotion_receipt")
    assert validate_champion_promotion_receipt_file(
        payload_path=receipt_path,
        repo_root=repo,
    ) == ()
    original_receipt_text = receipt_path.read_text(encoding="utf-8")
    tampered_receipt = json.loads(original_receipt_text)
    tampered_receipt["ok"] = False
    tampered_receipt["status"] = "blocked"
    tampered_receipt["approval_sha256"] = "wrong"
    tampered_receipt["source_dry_run_sha256"] = "wrong"
    tampered_receipt["evidence_checks"]["ok"] = False
    tampered_receipt["evidence_checks"]["blockers"] = ["wrong"]
    tampered_receipt["evidence_checks"]["expected_command"] = "wrong"
    tampered_receipt["evidence_checks"]["reviewed_command"] = "wrong"
    tampered_receipt["evidence_checks"]["current_champion_run_id"] = "wrong"
    tampered_receipt["comparison"]["recommendation"] = "keep_base"
    tampered_receipt["promotion_result"]["promoted"] = False
    tampered_receipt["promotion_result"]["comparison"]["candidate_run_id"] = "wrong"
    tampered_receipt["promotion_result"]["comparison"]["base_run_id"] = "wrong"
    tampered_receipt["policy"]["requires_approval_artifact"] = False
    receipt_path.write_text(
        json.dumps(tampered_receipt, indent=2, sort_keys=True),
        encoding="utf-8",
    )
    receipt_consistency_errors = validate_champion_promotion_receipt_file(
        payload_path=receipt_path,
        repo_root=repo,
    )
    for expected_error in (
        "champion_promotion_receipt ok false",
        "champion_promotion_receipt status mismatch",
        "champion_promotion_receipt promoted without evidence ok",
        "champion_promotion_receipt promoted with blockers",
        "champion_promotion_receipt approval digest mismatch",
        "champion_promotion_receipt dry-run digest mismatch",
        "champion_promotion_receipt expected command mismatch",
        "champion_promotion_receipt reviewed command mismatch",
        "champion_promotion_receipt base champion mismatch",
        "champion_promotion_receipt comparison recommendation mismatch",
        "champion_promotion_receipt promotion result mismatch",
        "champion_promotion_receipt promotion candidate mismatch",
        "champion_promotion_receipt promotion base mismatch",
        "champion_promotion_receipt policy false: requires_approval_artifact",
    ):
        assert expected_error in receipt_consistency_errors
    receipt_path.write_text(original_receipt_text, encoding="utf-8")
    artifact_report = validate_run_artifacts(
        run_id="receipt-candidate",
        experiments_dir=repo / "experiments",
        repo_root=repo,
    )
